import { useRef, useState, useEffect, useCallback } from 'react';
import {
  startOrEnd,
  getState,
  getEndStatus,
  getTimeout,
  nextTick,
} from '../utils/transitionHelpers';
import {
  PRE_ENTER,
  ENTERING,
  ENTERED,
  PRE_EXIT,
  EXITING,
} from '../constants/transitionsStatuses';

/**
 * @param {import('../constants/transitionsStatuses').Status} status
 * @param {Function} setState
 * @param {import('react').RefObject<import('../utils/transitionHelpers').State>} latestState
 * @param {import('react').RefObject<NodeJS.Timeout | undefined>} timeoutId
 * @param {({current}: {current: import('../utils/transitionHelpers').State}) => void} [onChange]
 */
const updateState = (status, setState, latestState, timeoutId, onChange) => {
  clearTimeout(timeoutId.current);
  const state = getState(status);
  setState(state);
  latestState.current = state;
  if (typeof onChange === 'function') {
    onChange({ current: state });
  }
};

/** @type {typeof import('@andes/common/build/hooks/useTransition').useTransition} */
const useTransition = ({
  enter = true,
  exit = true,
  preEnter,
  preExit,
  timeout,
  initialEntered,
  mountOnEnter,
  unmountOnExit,
  onStateChange: onChange,
} = {}) => {
  const [state, setState] = useState(() =>
    getState(initialEntered ? ENTERED : startOrEnd(mountOnEnter)),
  );
  const latestState = useRef(state);
  /** @type {import('react').RefObject<NodeJS.Timeout | undefined>} */
  const timeoutId = useRef(undefined);
  const [enterTimeout, exitTimeout] = getTimeout(timeout);

  const endTransition = useCallback(() => {
    // eslint-disable-next-line no-underscore-dangle
    const status = getEndStatus(latestState.current._s, unmountOnExit);
    if (status) {
      updateState(status, setState, latestState, timeoutId, onChange);
    }
  }, [onChange, unmountOnExit]);

  const toggle = useCallback(
    /** @param {boolean} [toEnter] */
    (toEnter) => {
      /** @param {import('../constants/transitionsStatuses').Status} status */
      const transitState = (status) => {
        updateState(status, setState, latestState, timeoutId, onChange);

        switch (status) {
          case ENTERING:
            if (enterTimeout && enterTimeout >= 0) timeoutId.current = setTimeout(endTransition, enterTimeout);
            break;

          case EXITING:
            if (exitTimeout && exitTimeout >= 0) timeoutId.current = setTimeout(endTransition, exitTimeout);
            break;

          case PRE_ENTER:
          case PRE_EXIT:
            timeoutId.current = nextTick(transitState, status);
            break;
          default:
            break;
        }
      };

      const enterStage = latestState.current.isEnter;
      // eslint-disable-next-line no-param-reassign
      if (typeof toEnter !== 'boolean') toEnter = !enterStage;

      if (toEnter) {
        if (!enterStage) {
          // eslint-disable-next-line no-nested-ternary
          transitState(enter ? (preEnter ? PRE_ENTER : ENTERING) : ENTERED);
        }
      } else if (enterStage) {
        // eslint-disable-next-line no-nested-ternary
        transitState(exit ? (preExit ? PRE_EXIT : EXITING) : startOrEnd(unmountOnExit));
      }
    },
    [
      endTransition,
      onChange,
      enter,
      exit,
      preEnter,
      preExit,
      enterTimeout,
      exitTimeout,
      unmountOnExit,
    ],
  );

  useEffect(() => () => clearTimeout(timeoutId.current), []);

  return [state, toggle, endTransition];
};

export { useTransition };
