import {
  ENTERED,
  ENTERING,
  EXITED,
  EXITING,
  PRE_ENTER,
  PRE_EXIT,
  STATUS,
  UNMOUNTED,
} from '../constants/transitionsStatuses';

/**
 * @typedef {Object} TimeoutObject
 * @property {number} [enter]
 * @property {number} [exit]
 */

/** @typedef {TimeoutObject | number } Timeout */

/**
 * @typedef {Object} State
 * @prop {number} _s
 * @prop {typeof STATUS[number]} status
 * @prop {boolean} isEnter
 * @prop {boolean} isMounted
 * @prop {boolean} isResolved
 */

/**
 * @param {import('../constants/transitionsStatuses').Status} status
 */
export const getState = (status) => ({
  _s: status,
  status: STATUS[status],
  isEnter: status < PRE_EXIT,
  isMounted: status !== UNMOUNTED,
  isResolved: status === ENTERED || status > EXITING,
});

/** @param {boolean} [unmounted] */
export const startOrEnd = (unmounted) => (unmounted ? UNMOUNTED : EXITED);

/**
 * @param {number} status
 * @param {boolean} [unmountOnExit]
 */
export const getEndStatus = (status, unmountOnExit) => {
  switch (status) {
    case ENTERING:
    case PRE_ENTER:
      return ENTERED;

    case EXITING:
    case PRE_EXIT:
      return startOrEnd(unmountOnExit);
    default:
      break;
  }
};

/** @param {Timeout} [timeout] */
export const getTimeout = (timeout) =>
  (typeof timeout === 'object'
    ? [timeout.enter, timeout.exit]
    : [timeout, timeout]);

/**
 * @param {Function} transitState
 * @param {import('../constants/transitionsStatuses').Status} status
 */
export const nextTick = (transitState, status) =>
  setTimeout(() => {
    // Reading document.body.offsetTop can force browser to repaint before transition to the next state
    // eslint-disable-next-line no-unused-expressions
    Number.isNaN(document.body.offsetTop) || transitState(status + 1);
  }, 0);
